                    {"id": 2, "question": "What two chemicals are essential for bioluminescence?", "options": ["Chlorophyll and oxygen", "Luciferin and luciferase", "Hemoglobin and iron", "Calcium and phosphorus"], "answer": "Luciferin and luciferase", "explanation": "The passage identifies luciferin (a molecule) and luciferase (an enzyme) as the chemicals involved."},
                    {"id": 3, "question": "Why is bioluminescent light typically blue-green?", "options": ["Blue-green light is the brightest", "Deep-sea organisms prefer that color", "Those wavelengths travel farthest through seawater", "It is the easiest color to produce chemically"], "answer": "Those wavelengths travel farthest through seawater", "explanation": "The passage explains that blue-green wavelengths travel farthest through seawater."},
                    {"id": 4, "question": "How does the anglerfish use bioluminescence?", "options": ["To communicate with mates", "To camouflage itself", "To attract prey with a luminous lure", "To warn predators"], "answer": "To attract prey with a luminous lure", "explanation": "The anglerfish has a luminous lure dangling above its mouth to attract smaller fish."},
